import { useState, useCallback } from 'react';
import { products, categories, getCategoryColor } from '../data/products';
import { analyticsAPI, localCart, localEvents } from '../services/api';
import { useAuth } from '../context/AuthContext';

const ProductsPage = ({ onToast }) => {
  const { user } = useAuth();
  const [category, setCategory] = useState('All');
  const [search, setSearch]     = useState('');
  const [modal, setModal]       = useState(null);

  const sessionId = sessionStorage.getItem('u_session') || (() => {
    const id = Math.random().toString(36).slice(2);
    sessionStorage.setItem('u_session', id); return id;
  })();

  const track = useCallback(async (product, actionType) => {
    const ev = { sessionId, userId: user?.id, productId: product.id, productName: product.name,
      category: product.category, price: product.price, emoji: product.emoji, brand: product.brand, actionType };
    localEvents.add({ ...ev, timestamp: new Date().toISOString() });
    window.dispatchEvent(new Event('eventsUpdated'));
    try { await analyticsAPI.track(ev); } catch {}
  }, [user, sessionId]);

  const viewProduct = (p) => { setModal(p); track(p, 'product_viewed'); };

  const addToCart = (p) => {
    const cart = localCart.get();
    const ex = cart.find(i => i.id === p.id);
    if (ex) ex.quantity++; else cart.push({ ...p, quantity: 1 });
    localCart.set(cart);
    window.dispatchEvent(new Event('cartUpdated'));
    track(p, 'add_to_cart');
    onToast?.(`🛒 ${p.name} added to cart!`, 'success');
  };

  const filtered = products.filter(p =>
    (category === 'All' || p.category === category) &&
    (p.name.toLowerCase().includes(search.toLowerCase()) || p.brand.toLowerCase().includes(search.toLowerCase()))
  );

  return (
    <div>
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-2">
        <div>
          <h4 className="fw-bold mb-1">🛍️ Products</h4>
          <p className="text-muted small mb-0">Browse {products.length} premium technology products</p>
        </div>
        <input type="text" className="form-control w-auto" placeholder="🔍 Search products..."
          value={search} onChange={e => setSearch(e.target.value)} style={{ minWidth: 220 }} />
      </div>

      {/* Category tabs */}
      <div className="d-flex gap-2 flex-wrap mb-4">
        {categories.map(c => (
          <button key={c} onClick={() => setCategory(c)}
            className={`btn btn-sm ${category === c ? 'btn-dark' : 'btn-outline-secondary'} fw-semibold`}>
            {c} <span className="badge bg-secondary ms-1">{c === 'All' ? products.length : products.filter(p => p.category === c).length}</span>
          </button>
        ))}
      </div>

      <p className="text-muted small mb-3">Showing {filtered.length} products</p>

      {filtered.length === 0 ? (
        <div className="text-center py-5 text-muted">
          <div style={{ fontSize: '3rem' }}>🔍</div>
          <p className="mt-2">No products found</p>
        </div>
      ) : (
        <div className="row g-3">
          {filtered.map(p => (
            <div key={p.id} className="col-xl-3 col-lg-4 col-md-6">
              <div className="card h-100 border-0 shadow-sm">
                <div className={`card-header bg-${getCategoryColor(p.category)} text-white text-center py-3`}>
                  <div style={{ fontSize: '3rem' }}>{p.emoji}</div>
                  <span className="badge bg-white text-dark mt-1 small">{p.category}</span>
                </div>
                <div className="card-body d-flex flex-column">
                  <h6 className="fw-bold mb-1 small">{p.name}</h6>
                  <span className="badge bg-light text-dark mb-1" style={{ fontSize: '0.65rem' }}>{p.brand}</span>
                  <p className="text-muted mb-2" style={{ fontSize: '0.7rem' }}>{p.specs}</p>
                  <div className="mt-auto">
                    <div className="fw-bold text-success fs-6 mb-2">₹{p.price.toLocaleString('en-IN')}</div>
                    <div className="d-grid gap-1">
                      <button className="btn btn-outline-primary btn-sm" onClick={() => viewProduct(p)}>👁️ View Details</button>
                      <button className="btn btn-warning btn-sm fw-bold" onClick={() => addToCart(p)}>🛒 Add to Cart</button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Product modal */}
      {modal && (
        <div className="modal show d-block" style={{ background: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg">
              <div className="modal-header bg-dark text-white">
                <h5 className="modal-title text-warning fw-bold">{modal.name}</h5>
                <button className="btn-close btn-close-white" onClick={() => setModal(null)} />
              </div>
              <div className="modal-body text-center p-4">
                <div style={{ fontSize: '5rem' }}>{modal.emoji}</div>
                <h5 className="fw-bold mt-2">{modal.name}</h5>
                <div className="d-flex gap-2 justify-content-center mb-2">
                  <span className="badge bg-primary">{modal.category}</span>
                  <span className="badge bg-secondary">{modal.brand}</span>
                </div>
                <p className="text-muted">{modal.specs}</p>
                <div className="fs-4 text-success fw-bold mb-1">₹{modal.price.toLocaleString('en-IN')}</div>
                <div className="small text-warning mb-3">{'⭐'.repeat(Math.floor(modal.rating))} {modal.rating}</div>
                <div className="alert alert-info py-2 small">📊 This view has been tracked in your analytics</div>
              </div>
              <div className="modal-footer">
                <button className="btn btn-warning fw-bold flex-grow-1" onClick={() => { addToCart(modal); setModal(null); }}>
                  🛒 Add to Cart — ₹{modal.price.toLocaleString('en-IN')}
                </button>
                <button className="btn btn-secondary" onClick={() => setModal(null)}>Close</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductsPage;
